package form;
import controller.PemasukanController;import model.*;import util.UIUtils;import com.github.lgooddatepicker.components.DatePicker;import javax.swing.*;import javax.swing.table.DefaultTableModel;import java.awt.*;import java.io.File;import java.sql.Date;import java.time.LocalDate;
public class PemasukanForm extends JPanel{PemasukanController c=new PemasukanController();DefaultTableModel m=new DefaultTableModel(new String[]{"ID","Tanggal","Siswa","Kategori","Nominal","Keterangan"},0);public PemasukanForm(User u){setLayout(new BorderLayout());JPanel p=UIUtils.page("Transaksi Pemasukan");JTabbedPane tabs=new JTabbedPane();tabs.addTab("Pembayaran SPP",spp(u));tabs.addTab("Penerimaan Lain & Riwayat",lain(u));p.add(tabs);add(p);}JPanel spp(User u){JPanel p=new JPanel(new BorderLayout());JTextField siswa=UIUtils.textField(6),bulan=UIUtils.textField(3),tahun=UIUtils.textField(4),nom=UIUtils.textField(10);JButton b=UIUtils.button("Proses Bayar",UIUtils.GREEN),pdf=UIUtils.button("Cetak Kuitansi PDF",UIUtils.ORANGE);b.addActionListener(e->{try{c.bayarSpp(Integer.parseInt(siswa.getText()),Integer.parseInt(bulan.getText()),Integer.parseInt(tahun.getText()),Double.parseDouble(nom.getText()),u.getId());JOptionPane.showMessageDialog(this,"Pembayaran tersimpan");}catch(Exception ex){JOptionPane.showMessageDialog(this,ex.getMessage());}});pdf.addActionListener(e->{try{c.cetakKuitansiPdf(new File("kuitansi-spp.pdf"),siswa.getText(),Double.parseDouble(nom.getText()),"SPP");JOptionPane.showMessageDialog(this,"PDF dibuat");}catch(Exception ex){JOptionPane.showMessageDialog(this,ex.getMessage());}});p.add(UIUtils.toolbar(UIUtils.formLabel("ID Siswa"),siswa,UIUtils.formLabel("Bulan"),bulan,UIUtils.formLabel("Tahun"),tahun,UIUtils.formLabel("Nominal"),nom,b,pdf),BorderLayout.NORTH);return p;}JPanel lain(User u){JPanel p=new JPanel(new BorderLayout());DatePicker a=new DatePicker(),b=new DatePicker();a.setDate(LocalDate.now().minusMonths(1));b.setDate(LocalDate.now());JTextField kat=UIUtils.textField(10),nom=UIUtils.textField(10),ket=UIUtils.textField(20);JButton sim=UIUtils.button("Simpan",UIUtils.BLUE),filter=UIUtils.button("Filter",UIUtils.CYAN);sim.addActionListener(e->{try{c.simpan(new Pemasukan(0,Date.valueOf(LocalDate.now()),null,2,Double.parseDouble(nom.getText()),ket.getText(),u.getId()));load(a.getDate(),b.getDate(),kat.getText());}catch(Exception ex){JOptionPane.showMessageDialog(this,ex.getMessage());}});filter.addActionListener(e->load(a.getDate(),b.getDate(),kat.getText()));p.add(UIUtils.toolbar(UIUtils.formLabel("Dari"),a,UIUtils.formLabel("Sampai"),b,UIUtils.formLabel("Kategori"),kat,UIUtils.formLabel("Nominal"),nom,UIUtils.formLabel("Ket"),ket,sim,filter),BorderLayout.NORTH);p.add(UIUtils.tableScroll(new JTable(m)));load(a.getDate(),b.getDate(),"");return p;}void load(LocalDate a,LocalDate b,String k){m.setRowCount(0);try{for(Object[] r:c.riwayat(a,b,k))m.addRow(r);}catch(Exception ignored){}}}
